function buildFigmaHeroDots(): HeroDot[] {
  const dots: HeroDot[] = [];
  const addRibbon = ({
    amplitude,
    centerY,
    opacity,
    phase,
    radius,
    rowGap,
    rows,
    step,
  }: {
    amplitude: number;
    centerY: number;
    opacity: number;
    phase: number;
    radius: number;
    rowGap: number;
    rows: number;
    step: number;
  }) => {
    let dotIndex = 0;
    for (let x = -170; x <= 1610; x += step) {
      const theta = (x + phase) / 170;
      const center =
        centerY +
        Math.sin(theta) * amplitude +
        Math.sin(theta * 0.58 + phase) * 36;
      const slope = Math.cos(theta) * 0.9;
      for (let row = -rows; row <= rows; row += 1) {
        const edge = Math.abs(row) / rows;
        const waveLift = Math.cos(theta * 1.4 + row * 0.12) * row * 1.25;
        dots.push({
          cx: Number((x + row * slope * 9).toFixed(2)),
          cy: Number((center + row * rowGap + waveLift).toFixed(2)),
          opacity: Number(
            (
              opacity *
              (1 - edge * 0.62) *
              (0.76 + 0.24 * Math.sin(theta + row * 0.16 + dotIndex * 0.01))
            ).toFixed(3)
          ),
          r: Number(
            (
              radius *
              (1 - edge * 0.38) *
              (0.82 + 0.18 * Math.cos(theta * 1.7))
            ).toFixed(2)
          ),
        });
        dotIndex += 1;
      }
    }
  };

  addRibbon({
    amplitude: 118,
    centerY: 505,
    opacity: 0.82,
    phase: -120,
    radius: 2.1,
    rowGap: 8.4,
    rows: 18,
    step: 18,
  });
  addRibbon({
    amplitude: 86,
    centerY: 628,
    opacity: 0.62,
    phase: 190,
    radius: 1.45,
    rowGap: 7.1,
    rows: 13,
    step: 19,
  });
  return dots;
}

const FIGMA_HERO_DOTS = buildFigmaHeroDots();

function formatCompactCurrency(value: unknown, decimals = 1): string {
  const n = Number(value);
  if (!Number.isFinite(n)) return "$2.4B+";
  if (n >= 1e12) return `$${(n / 1e12).toFixed(decimals)}T`;
  if (n >= 1e9) return `$${(n / 1e9).toFixed(decimals)}B`;
  if (n >= 1e6) return `$${(n / 1e6).toFixed(decimals)}M`;
  if (n >= 1e3) return `$${(n / 1e3).toFixed(decimals)}K`;
  return `$${n.toFixed(0)}`;
}

function formatCount(value: number): string {
  return Math.floor(value).toLocaleString();
}

function getLatestActiveBuilderCount(
  rows: OrderlyDashboardMainRow[]
): number | null {
  let latestCount: number | null = null;
  let latestTime = Number.NEGATIVE_INFINITY;
  let latestIndex = -1;
  rows.forEach((row, index) => {
    const count = Number(row.active_builders_count);
    if (!Number.isFinite(count)) return;
    const time = row.date ? Date.parse(row.date) : NaN;
    const comparableTime = Number.isFinite(time) ? time : index;
    if (
      comparableTime > latestTime ||
      (comparableTime === latestTime && index > latestIndex)
    ) {
      latestTime = comparableTime;
      latestIndex = index;
      latestCount = count;
    }
  });
  return latestCount;
}

function BuilderLaunchCta({
  session,
  children,
}: {
  session: PublicSession;
  children: React.ReactNode;
}) {
  const { t } = useTranslation();

  if (session.isAmbassadorDistributor) {
    return (
      <OdsButton variant="secondary" size="large" disabled>
        {t("landing.notApplicable")}
      </OdsButton>
    );
  }

  return (
    <OdsButton asChild variant="primary" size="large" className="gap-2">
      <LocalizedLink to={session.isLoggedIn ? session.dashboardPath : "/login"}>
        {session.isLoggedIn ? t("landing.goToDashboard") : children}
        <ArrowRight className="h-4 w-4" />
      </LocalizedLink>
    </OdsButton>
  );
}

function AnimatedMetric({
  value,
  fallback,
  format,
}: {
  value: number | null;
  fallback: string;
  format: "currency" | "number";
}) {
  const [displayValue, setDisplayValue] = useState(0);

  useEffect(() => {
    if (value === null) return;
    let frameId = 0;
    const start = performance.now();
    const duration = 1100;

    const tick = (now: number) => {
      const linearProgress = Math.min((now - start) / duration, 1);
      const acceleratingProgress = linearProgress * linearProgress;
      setDisplayValue(value * acceleratingProgress);
      if (linearProgress < 1) frameId = requestAnimationFrame(tick);
    };

    setDisplayValue(0);
    frameId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameId);
  }, [value]);

  if (value === null) return <>{fallback}</>;
  return (
    <>
      {format === "currency"
        ? formatCompactCurrency(displayValue)
        : formatCount(displayValue)}
    </>
  );
}

