export default function LandingPage() {
  const { t } = useTranslation();
  const [publicSession, setPublicSession] = useState<PublicSession>(() =>
    getPublicSession()
  );
  const [metricValues, setMetricValues] = useState<
    Record<StatMetric, number | null>
  >({
    totalVolume: null,
    liveBuilders: null,
    chainsSupported: null,
    tvl: null,
    openInterest: null,
    volume24h: null,
  });

  useEffect(() => {
    function refreshSession() {
      setPublicSession(getPublicSession());
    }

    window.addEventListener("authChanged", refreshSession);
    window.addEventListener("profileUpdated", refreshSession);
    window.addEventListener("storage", refreshSession);
    return () => {
      window.removeEventListener("authChanged", refreshSession);
      window.removeEventListener("profileUpdated", refreshSession);
      window.removeEventListener("storage", refreshSession);
    };
  }, []);

  useEffect(() => {
    let cancelled = false;
    Promise.allSettled([
      fetchPublicVolumeStats(),
      fetchOrderlyDashboardMainStats(),
      fetchPublicFutures(),
      fetchPublicChainInfo(),
      fetchPublicBalanceStats(),
    ]).then(
      ([
        volumeResult,
        dashboardResult,
        futuresResult,
        chainResult,
        balanceResult,
      ]) => {
        if (cancelled) return;
        const volumeStats =
          volumeResult.status === "fulfilled" ? volumeResult.value : null;
        if (volumeStats?.perp_volume_ltd !== undefined) {
          setMetricValues(current => ({
            ...current,
            totalVolume: Number(volumeStats.perp_volume_ltd) || 0,
          }));
        }
        if (dashboardResult.status === "fulfilled") {
          const activeBuilders = getLatestActiveBuilderCount(
            dashboardResult.value
          );
          if (activeBuilders !== null)
            setMetricValues(current => ({
              ...current,
              liveBuilders: activeBuilders,
            }));
        }
        if (futuresResult.status === "fulfilled") {
          const futures = futuresResult.value;
          const totalOpenInterest = futures.reduce((sum, row) => {
            const openInterest = Number(row.open_interest) || 0;
            const indexPrice = Number(row.index_price) || 0;
            return sum + openInterest * indexPrice;
          }, 0);
          const total24hAmount = futures.reduce(
            (sum, row) => sum + (Number(row["24h_amount"]) || 0),
            0
          );
          setMetricValues(current => ({
            ...current,
            openInterest: totalOpenInterest,
            volume24h: total24hAmount,
          }));
        }
        if (chainResult.status === "fulfilled") {
          setMetricValues(current => ({
            ...current,
            chainsSupported: chainResult.value.length,
          }));
        }
        const balanceStats =
          balanceResult.status === "fulfilled" ? balanceResult.value : null;
        if (balanceStats?.total_holding !== undefined) {
          setMetricValues(current => ({
            ...current,
            tvl: Number(balanceStats.total_holding) || 0,
          }));
        }
      }
    );
    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <div className="min-h-screen bg-[var(--bg-base)]">
      <section className="relative overflow-hidden px-6 pb-20 pt-16">
        <FigmaHeroBackground />
        <div className="relative mx-auto max-w-[1200px] text-center">
          <h1 className="mb-6 text-5xl font-semibold leading-tight text-[var(--fg-base)] sm:text-6xl">
            {t("landing.heroBuild")}
            <br />
            <span className="text-[var(--fg-base)]">
              {t("landing.heroOwn")}
            </span>
          </h1>
          <p className="mx-auto mb-10 max-w-[640px] text-base leading-[24.8889px] text-[var(--fg-secondary)]">
            {t("landing.subtitle")}
          </p>
          <div className="flex flex-col items-center justify-center gap-4 sm:flex-row">
            <BuilderLaunchCta session={publicSession}>
              {t("common.getStarted")}
            </BuilderLaunchCta>
            <OdsButton asChild variant="secondary" size="large">
              <LocalizedLink to="/board">
                {t("landing.viewLeaderboard")}
              </LocalizedLink>
            </OdsButton>
          </div>
        </div>
      </section>

      <section className="px-6 pb-20">
        <div className="mx-auto max-w-[1200px]">
          <div className="mb-12 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
            {STATS.map(stat => (
              <div
                key={stat.labelKey}
                className="rounded-xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] p-6 text-center"
              >
                <div className="mb-1 text-3xl font-semibold text-[var(--fg-base)]">
                  <AnimatedMetric
                    value={metricValues[stat.metric]}
                    fallback={stat.fallback}
                    format={stat.format}
                  />
                </div>
                <div className="text-sm text-[var(--fg-secondary)]">
                  {t(`landing.${stat.labelKey}`)}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="px-6 pb-20">
        <div className="mx-auto max-w-[1200px]">
          <div className="mb-10 text-center">
            <h2 className="mb-3 text-3xl font-semibold text-[var(--fg-base)]">
              {t("landing.everythingTitle")}
            </h2>
            <p className="text-[var(--fg-secondary)]">
              {t("landing.everythingDesc")}
            </p>
          </div>
          <div className="grid grid-cols-1 gap-5 sm:grid-cols-2">
            {FEATURES.map(feature => (
              <div
                key={feature.titleKey}
                className="rounded-xl border border-[var(--border-subtle)] bg-[var(--bg-surface-primary)] p-6"
              >
                <div className="mb-4 flex h-10 w-10 items-center justify-center rounded-lg bg-[var(--bg-primary-subtle)] text-[var(--fg-primary)]">
                  <feature.icon className="h-5 w-5" />
                </div>
                <h3 className="mb-2 text-base font-medium text-[var(--fg-base)]">
                  {t(`landing.${feature.titleKey}`)}
                </h3>
                <p className="text-sm text-[var(--fg-secondary)]">
                  {t(`landing.${feature.descriptionKey}`)}
                </p>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="px-6 pb-20">
        <div className="mx-auto max-w-[1200px] p-10 text-center">
          <h2 className="mb-3 text-3xl font-semibold text-[var(--fg-base)]">
            {t("landing.readyTitle")}
          </h2>
          <p className="mx-auto mb-8 max-w-[480px] text-[var(--fg-secondary)]">
            {t("landing.readyDesc")}
          </p>
          <BuilderLaunchCta session={publicSession}>
            {t("common.getStarted")}
          </BuilderLaunchCta>
        </div>
      </section>

      <OdsFooter />
    </div>
  );
}
